const body = $input.first().json.body;

// ─── EXTRACT LATEST REPLY ────────────────────────────────────────────────────
const campaignName = body.campaign?.name || '';
const messages = body.recent_messages || [];
const latestReply = messages.find(m => m.is_reply === true);
const messageText = latestReply?.message || '';
const messageTimestamp = latestReply?.creation_time || body.timestamp || '';

// ─── FORMAT DATES ────────────────────────────────────────────────────────────
const replyDate = new Date(messageTimestamp);

const dateFormatted = (replyDate.getMonth() + 1).toString().padStart(2, '0') + '/' +
                       replyDate.getDate().toString().padStart(2, '0') + '/' +
                       replyDate.getFullYear();

const fullTimestamp = replyDate.toISOString().replace('T', ' ').split('.')[0];

// Month → YYYY-MM (for Looker Studio filter)
const monthFormatted = replyDate.getFullYear() + '-' +
  (replyDate.getMonth() + 1).toString().padStart(2, '0');

// Week start (Monday) → YYYY-MM-DD
const dayOfWeek = replyDate.getDay();
const diff = (dayOfWeek === 0 ? -6 : 1 - dayOfWeek);
const weekStart = new Date(replyDate);
weekStart.setDate(replyDate.getDate() + diff);
const weekFormatted = weekStart.getFullYear() + '-' +
  (weekStart.getMonth() + 1).toString().padStart(2, '0') + '-' +
  weekStart.getDate().toString().padStart(2, '0');

// ─── TYPE ────────────────────────────────────────────────────────────────────
const messageType = body.is_inmail === true ? 'InMail' : 'Connect';

return {
  prospect_name:        body.lead?.full_name || '',
  prospect_linkedin:    body.lead?.profile_url || '',
  prospect_company:     body.lead?.company_name || '',
  prospect_position:    body.lead?.position || '',
  prospect_email:       body.lead?.email_address || body.lead?.enriched_email || body.lead?.custom_email || '',
  prospect_phone:       '',
  prospect_first_name:  body.lead?.first_name || '',
  prospect_last_name:   body.lead?.last_name || '',
  prospect_location:    body.lead?.location || '',
  prospect_summary:     body.lead?.summary || '',

  setter_name:          body.sender?.full_name || '',
  setter_email:         body.sender?.email_address || '',
  setter_linkedin:      body.sender?.profile_url || '',
  setter_id:            body.sender?.id || '',

  campaign_name:        campaignName,
  campaign_name_lower:  campaignName.toLowerCase(),   // ← NEW: used for matching
  campaign_id:          body.campaign?.id || '',
  campaign_status:      body.campaign?.status || '',

  message_type:         messageType,
  notes_replies:        messageText,
  status_warm:          'Interested (Warm)',
  status_booked:        'DC Booked',

  date:                 dateFormatted,
  month:                monthFormatted,               // ← NEW
  week:                 weekFormatted,                // ← NEW
  timestamp:            fullTimestamp,
  raw_timestamp:        body.timestamp || '',

  is_inmail:            body.is_inmail || false,
  event_type:           body.event_type || '',
  conversation_id:      body.conversation_id || '',
};

