// ─── DYNAMIC CLIENT LOOKUP FROM MASTER SHEET ─────────────────────────────────
// Previous node (Get Clients from Master Sheet) passes all rows from the
// Clients tab. Each row: Client | Sheet ID | Status
// We match campaign name against client name keywords.

const setData       = $('Set Data').first().json;
const clientRows    = $input.all();
const campaignLower = setData.campaign_name_lower || '';

const MASTER_SHEET_ID = '1QdTaEMlMR5jbiVKX_cIAZU-Efoc5LhQHftmPIrb0GrI';
const MASTER_WARM_TAB = 'Warm Leads';
const MASTER_DC_TAB   = 'DC Booked';

// ─── MATCH ────────────────────────────────────────────────────────────────────
let matchedClient = null;

for (const row of clientRows) {
  const clientName = (row.json['Client'] || '').trim();
  const status     = (row.json['Status'] || '').trim().toLowerCase();
  const sheetId    = (row.json['Sheet ID'] || '').trim();

  if (status !== 'active') continue;
  if (!clientName || !sheetId) continue;

  const keywords = clientName.toLowerCase()
    .split(' ')
    .filter(w => w.length > 2 && !['the','and','for','llc','inc'].includes(w));

  const allMatch = keywords.every(kw => campaignLower.includes(kw));

  if (allMatch) {
    matchedClient = { clientName, sheetId };
    break;
  }
}

// ─── OUTPUT ───────────────────────────────────────────────────────────────────
if (!matchedClient) {
  return {
    client_found:    false,
    client:          'Unknown — ' + setData.campaign_name,
    sheet_id:        null,
    warm_tab:        'Warm Leads',
    dc_booked_tab:   'DC Booked',
    master_sheet_id: MASTER_SHEET_ID,
    master_warm_tab: MASTER_WARM_TAB,
    master_dc_tab:   MASTER_DC_TAB,
    ...setData,
  };
}

return {
  client_found:    true,
  client:          matchedClient.clientName,
  sheet_id:        matchedClient.sheetId,
  warm_tab:        'Warm Leads',
  dc_booked_tab:   'DC Booked',
  master_sheet_id: MASTER_SHEET_ID,
  master_warm_tab: MASTER_WARM_TAB,
  master_dc_tab:   MASTER_DC_TAB,
  ...setData,
};

